        "reason": string,
        "answer": boolean
    },
    "is_progress_being_made": {
        "reason": string,
        "answer": boolean
    },
    "next_speaker": {
        "reason": string,
        "answer": string (select from: ReqMaster)
    },
    "instruction_or_question": {
        "reason": string,
        "answer": string
    }
}

